using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Options with a default (reflection-based) resolver ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns JsonTypeInfo<T> directly, no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"  Serialized: {json}");

Person? p = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"  Deserialized: {p}");

// 2) TryGetTypeInfo<T>() — probe without throwing.
//    Person should succeed (resolver handles it).
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
    Console.WriteLine($"\nTryGetTypeInfo<Person> → found ({info!.Type.Name})");
else
    Console.WriteLine("\nTryGetTypeInfo<Person> → NOT found");

// Now try with options that have an empty custom resolver —
// no types are configured, so TryGetTypeInfo returns false.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
        .WithAddedModifier(ti =>
        {
            // Only allow string metadata through
            if (ti.Type != typeof(string))
                throw new NotSupportedException($"Type {ti.Type} not supported");
        })
};

if (limited.TryGetTypeInfo<Person>(out _))
    Console.WriteLine("TryGetTypeInfo<Person> on limited options → found");
else
    Console.WriteLine("TryGetTypeInfo<Person> on limited options → NOT found (no exception thrown!)");

// Prove that string still works on the limited resolver
if (limited.TryGetTypeInfo<string>(out JsonTypeInfo<string>? strInfo))
    Console.WriteLine($"TryGetTypeInfo<string>  on limited options → found ({strInfo!.Type.Name})");

public record Person(string Name, int Age);

